To start a new process with one file descriptor connected to its input and output in C++, you can use the `fork()` system call to create a new process and then use `dup2()` to redirect the file descriptor. Here’s a basic example:

```cpp
#include <unistd.h>
#include <fcntl.h>
#include <sys/wait.h>
#include <iostream>

int main() {
    int fd[2];
    if (pipe(fd) == -1) {
        std::cerr << "Pipe failed" << std::endl;
        return 1;
    }

    pid_t pid = fork();
    if (pid == -1) {
        std::cerr << "Fork failed" << std::endl;
        return 1;
    }

    if (pid == 0) { // Child process
        // Close unnecessary file descriptors
        close(fd[1]);
        dup2(fd[0], STDIN_FILENO);
        dup2(fd[0], STDOUT_FILENO);
        close(fd[0]);

        // Execute the child process
        execlp("your_command", "your_command", (char*)0);
        std::cerr << "Exec failed" << std::endl;
        _exit(1);
    } else { // Parent process
        // Close unnecessary file descriptors
        close(fd[0]);
        wait(NULL); // Wait for the child to finish
    }

    return 0;
}
```

Replace `"your_command"` with the command you want to run in the child process. This code creates a pipe, forges a new process, and redirects the pipe to the standard input and output of the child process.
